const inscriptions = $input.item.json;

// inscriptions est un tableau [{session_id, presence}, ...]
// Compter par session_id (seulement les confirmés, le filtre est dans la requête)
const counts = {};

if (Array.isArray(inscriptions)) {
  for (const insc of inscriptions) {
    const sid = (insc.session_id || '').trim();
    if (!sid) continue;
    if (!counts[sid]) counts[sid] = { total: 0 };
    counts[sid].total++;
  }
} else if (inscriptions && typeof inscriptions === 'object') {
  // Si l'API retourne l'array dans le body directement
  const items = Array.isArray(inscriptions.body) ? inscriptions.body : [];
  for (const insc of items) {
    const sid = (insc.session_id || '').trim();
    if (!sid) continue;
    if (!counts[sid]) counts[sid] = { total: 0 };
    counts[sid].total++;
  }
}

return { counts, totalConfirmes: Object.values(counts).reduce((s, c) => s + c.total, 0) };

const counts = $('2. Compter par session').item.json.counts;
const sessions = $input.item.json.data?.boards?.[0]?.items_page?.items || [];
const DEFAULT_WAITLIST = 10;
const result = {};

for (const session of sessions) {
  const capCol = session.column_values.find(c => c.id === 'numeric_mkx3vw7');
  const capacite = parseInt(capCol?.text || '0') || 0;

  if (capacite <= 0) continue;

  const waitCol = session.column_values.find(c => c.id === 'numeric_mm0zhzap');
  const attente_max = parseInt(waitCol?.text || '0') || DEFAULT_WAITLIST;

  const sc = counts[session.id] || { total: 0 };
  const total = sc.total;
  const places_restantes = Math.max(0, capacite - total);
  const places_attente_restantes = Math.max(0, (capacite + attente_max) - total);

  let statut = 'ouvert';
  if (total >= capacite + attente_max) {
    statut = 'complet';
  } else if (total >= capacite) {
    statut = 'liste_attente';
  }

  result[session.id] = {
    nom: session.name,
    inscrits: total,
    capacite,
    attente: Math.max(0, total - capacite),
    attente_max,
    places_restantes,
    places_attente_restantes,
    statut
  };
}

return [{ json: { success: true, sessions: result } }];
